import{_ as o,o as e,c as a,ag as i}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Script Tools Overview","description":"","frontmatter":{},"headers":[],"relativePath":"settings/tools.md","filePath":"settings/tools.md","lastUpdated":1776650765000}'),s={name:"settings/tools.md"};function r(l,t,n,d,h,c){return e(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="script-tools-overview" tabindex="-1">Script Tools Overview <a class="header-anchor" href="#script-tools-overview" aria-label="Permalink to &quot;Script Tools Overview&quot;">​</a></h1><p>EasyYapi provides a set of built-in tools that can be used in Groovy scripts within configuration rules. These tools are automatically available as variables in all Groovy script contexts.</p><h2 id="available-tools" tabindex="-1">Available Tools <a class="header-anchor" href="#available-tools" aria-label="Permalink to &quot;Available Tools&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Description</th></tr></thead><tbody><tr><td><a href="./tools/it">it</a></td><td>Current context object - the most important tool providing access to the element being processed</td></tr><tr><td><a href="./tools/tool">tool</a></td><td>General utility methods for string manipulation, collections, JSON, and more</td></tr><tr><td><a href="./tools/regex">regex</a></td><td>Regular expression utilities with pattern caching for performance</td></tr><tr><td><a href="./tools/logger">logger</a></td><td>Logging utility for debugging and information output</td></tr><tr><td><a href="./tools/helper">helper</a></td><td>Common operation helpers for type resolution and other utilities</td></tr><tr><td><a href="./tools/httpClient">httpClient</a></td><td>HTTP client for making requests in scripts</td></tr><tr><td><a href="./tools/localStorage">localStorage</a></td><td>Persistent local storage that survives IDE restarts</td></tr><tr><td><a href="./tools/session">session</a></td><td>Session-level storage cleared when IDE is restarted</td></tr><tr><td><a href="./tools/config">config</a></td><td>Configuration access for reading rule values</td></tr><tr><td><a href="./tools/api">api</a></td><td>API utilities for modifying endpoint metadata</td></tr><tr><td><a href="./tools/runtime">runtime</a></td><td>Runtime information about the environment</td></tr><tr><td><a href="./tools/fieldContext">fieldContext</a></td><td>Field context utilities for JSON path operations</td></tr><tr><td><a href="./tools/files">files</a></td><td>File operations for reading and writing files</td></tr></tbody></table><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><p>Tools are available as variables in Groovy scripts:</p><div class="language-properties vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">properties</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">field.mock</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=groovy:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">if (it.type().name() == &quot;java.lang.String&quot;) {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    return &quot;mock_string&quot;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">}</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">logger.info(&quot;Generating mock for: &quot; + it.name())</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;&#39;&#39;</span></span></code></pre></div><h2 id="tool-categories" tabindex="-1">Tool Categories <a class="header-anchor" href="#tool-categories" aria-label="Permalink to &quot;Tool Categories&quot;">​</a></h2><h3 id="context-tools" tabindex="-1">Context Tools <a class="header-anchor" href="#context-tools" aria-label="Permalink to &quot;Context Tools&quot;">​</a></h3><ul><li><strong>it</strong> - The primary context object. Its type depends on the rule context: <ul><li>Class rules → <code>ScriptPsiClassContext</code></li><li>Method rules → <code>ScriptPsiMethodContext</code></li><li>Field rules → <code>ScriptPsiFieldContext</code></li><li>Parameter rules → <code>ScriptPsiParameterContext</code></li></ul></li></ul><h3 id="storage-tools" tabindex="-1">Storage Tools <a class="header-anchor" href="#storage-tools" aria-label="Permalink to &quot;Storage Tools&quot;">​</a></h3><ul><li><strong>localStorage</strong> - Persistent storage that survives IDE restarts</li><li><strong>session</strong> - Temporary storage cleared on IDE restart</li></ul><h3 id="utility-tools" tabindex="-1">Utility Tools <a class="header-anchor" href="#utility-tools" aria-label="Permalink to &quot;Utility Tools&quot;">​</a></h3><ul><li><strong>tool</strong> - String manipulation, collections, JSON operations</li><li><strong>regex</strong> - Regular expression matching and extraction</li><li><strong>helper</strong> - Type resolution and common operations</li><li><strong>files</strong> - File I/O operations</li></ul><h3 id="communication-tools" tabindex="-1">Communication Tools <a class="header-anchor" href="#communication-tools" aria-label="Permalink to &quot;Communication Tools&quot;">​</a></h3><ul><li><strong>httpClient</strong> - HTTP requests</li><li><strong>config</strong> - Configuration access</li><li><strong>api</strong> - API endpoint modification</li></ul><h3 id="information-tools" tabindex="-1">Information Tools <a class="header-anchor" href="#information-tools" aria-label="Permalink to &quot;Information Tools&quot;">​</a></h3><ul><li><strong>logger</strong> - Logging output</li><li><strong>runtime</strong> - Environment information</li><li><strong>fieldContext</strong> - JSON path context</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../config-rule">Config Rules</a> - How to use tools in configuration rules</li><li><a href="./../events/">Events</a> - Event hooks where scripts can be used</li></ul>`,20)])])}const u=o(s,[["render",r]]);export{g as __pageData,u as default};
